import redis

def run_lua_script_with_redis(host='localhost', port=6379, db=0):
    """
    Connects to Redis, accepts a Lua script and parameters from user input,
    and executes the script using redis.eval().
    """
    try:
        r = redis.Redis(host=host, port=port, db=db, decode_responses=True)
        r.ping()
        print("Successfully connected to Redis.")
    except redis.exceptions.ConnectionError as e:
        print(f"Could not connect to Redis: {e}")
        return

    print("\nEnter your Lua script (type 'END' on a new line to finish):")
    lua_script_lines = []
    while True:
        line = input()
        if line == 'END':
            break
        lua_script_lines.append(line)
    lua_script = "\n".join(lua_script_lines)

    if not lua_script.strip():
        print("No Lua script provided. Exiting.")
        return

    print("\nEnter the number of keys to pass to the Lua script:")
    num_keys_str = input("Number of keys: ")
    try:
        num_keys = int(num_keys_str)
        if num_keys < 0:
            raise ValueError
    except ValueError:
        print("Invalid number of keys. Must be a non-negative integer. Exiting.")
        return

    keys = []
    for i in range(num_keys):
        key = input(f"Enter key {i+1}: ")
        keys.append(key)

    print("\nEnter the number of arguments (ARGV) to pass to the Lua script:")
    num_args_str = input("Number of arguments: ")
    try:
        num_args = int(num_args_str)
        if num_args < 0:
            raise ValueError
    except ValueError:
        print("Invalid number of arguments. Must be a non-negative integer. Exiting.")
        return

    args = []
    for i in range(num_args):
        arg = input(f"Enter argument {i+1}: ")
        args.append(arg)

    print("\nExecuting Lua script...")
    print(f"Script:\n{lua_script}")
    print(f"Keys: {keys}")
    print(f"Args: {args}")

    try:
        result = r.eval(lua_script, num_keys, *keys, *args)
        print("\n--- Lua Script Result ---")
        print(result)
        print("-------------------------\n")
    except redis.exceptions.RedisError as e:
        print(f"\nError executing Lua script: {e}")
    except Exception as e:
        print(f"\nAn unexpected error occurred: {e}")

if __name__ == "__main__":
    # You can change these parameters if your Redis server is not on default host/port
    run_lua_script_with_redis(host='localhost', port=6379, db=0)